    // Preprocess the array to create a frequency map for every possible subarray
    // However, directly precomputing for all subarrays is not feasible due to time constraints
    // Instead, we process each query individually

    for (auto& query : queries) {
        long long l = query[0], r = query[1], threshold = query[2];
        std::map<long long, int> freq;

        // Count frequency of elements in the subarray nums[l...r]
        for (int i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }

        long long best_val = -1;
        int best_freq = 0;

        // Find the element with the highest frequency (and smallest value in case of tie)
        for (const auto& [num, count] : freq) {
            if (count >= threshold) {
                if (count > best_freq || (count == best_freq && num < best_val)) {
                    best_val = num;
                    best_freq = count;
                }
            }
        }

        ans.push_back(best_val);
