using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> ans;
    int n = nums.size();

    // Preprocess: for each index, store the positions of each number
    map<long long, vector<int>> pos_map;
    for (int i = 0; i < n; ++i) {
        pos_map[nums[i]].push_back(i);
    }

    for (auto& query : queries) {
        int l = query[0], r = query[1], threshold = query[2];
        map<long long, int> freq;
        bool found = false;
        long long result = -1;

        // For each number in the subarray, count its frequency
        for (auto& [num, positions] : pos_map) {
            // Find the first position >= l and <= r
            auto it = lower_bound(positions.begin(), positions.end(), l);
            if (it != positions.end() && *it <= r) {
                // Count how many times num appears in [l, r]
                int count = upper_bound(positions.begin(), positions.end(), r) - it;
                if (count >= threshold) {
                    freq[num] = count;
                    found = true;
                }
            }
        }

        // Find the element with the highest frequency (smallest in case of tie)
        if (found) {
            long long max_freq = -1;
            long long best_num = -1;
            for (auto& [num, count] : freq) {
                if (count > max_freq || (count == max_freq && num < best_num)) {
                    max_freq = count;
                    best_num = num;
                }
            }
            ans.push_back(best_num);
        } else {
            ans.push_back(-1);
        }
    }

    return ans;
}
